import numpy as np

class StateGeneratorQGAN:
    """QGAN for quantum state generation."""

    def __init__(self, n_qubits: int, n_layers: int = 3):
        self.n_qubits = n_qubits
        self.n_layers = n_layers
        self.dim = 2**n_qubits
        # Parameters: RY and RZ per qubit per layer
        self.params = np.random.randn(n_layers * 2 * n_qubits) * 0.1

    def _ry_gate(self, theta: float) -> np.ndarray:
        c, s = np.cos(theta/2), np.sin(theta/2)
        return np.array([[c, -s], [s, c]])

    def _rz_gate(self, theta: float) -> np.ndarray:
        return np.array([[np.exp(-1j*theta/2), 0],
                        [0, np.exp(1j*theta/2)]])

    def _apply_gate(self, state: np.ndarray, gate: np.ndarray,
                    qubit: int) -> np.ndarray:
        n_qubits = int(np.log2(len(state)))
        full_gate = np.eye(1)
        for q in range(n_qubits):
            full_gate = np.kron(full_gate, gate if q == qubit else np.eye(2))
        return full_gate @ state

    def generate_state(self) -> np.ndarray:
        """Generate quantum state from circuit."""
        state = np.zeros(self.dim, dtype=complex)
        state[0] = 1.0

        params_per_layer = 2 * self.n_qubits
        for layer in range(self.n_layers):
            layer_params = self.params[layer*params_per_layer:
                                       (layer+1)*params_per_layer]

            # Apply RY rotations
            for q in range(self.n_qubits):
                ry = self._ry_gate(layer_params[q])
                state = self._apply_gate(state, ry, q)

            # Apply RZ rotations
            for q in range(self.n_qubits):
                rz = self._rz_gate(layer_params[self.n_qubits + q])
                state = self._apply_gate(state, rz, q)

            # Entanglement (CZ-like effect)
            if layer < self.n_layers - 1:
                for q in range(self.n_qubits - 1):
                    for i in range(self.dim):
                        bits = format(i, f'0{self.n_qubits}b')
                        if bits[q] == '1' and bits[q+1] == '1':
                            state[i] *= -1

        return state / np.linalg.norm(state)

    def compute_fidelity(self, target: np.ndarray) -> float:
        """Compute fidelity with target state."""
        generated = self.generate_state()
        inner_product = np.vdot(target, generated)
        return np.abs(inner_product)**2

    def create_ghz_target(self) -> np.ndarray:
        """Create GHZ state as target."""
        state = np.zeros(self.dim, dtype=complex)
        state[0] = 1/np.sqrt(2)      # |00...0⟩
        state[-1] = 1/np.sqrt(2)     # |11...1⟩
        return state

    def create_w_target(self) -> np.ndarray:
        """Create W state as target."""
        state = np.zeros(self.dim, dtype=complex)
        # W state has exactly one 1 in each basis state
        for i in range(self.n_qubits):
            basis_idx = 1 << (self.n_qubits - 1 - i)
            state[basis_idx] = 1/np.sqrt(self.n_qubits)
        return state

    def create_cluster_target(self) -> np.ndarray:
        """Create 1D cluster state."""
        # Start with |+⟩^n
        state = np.ones(self.dim, dtype=complex) / np.sqrt(self.dim)

        # Apply CZ between adjacent qubits
        for q in range(self.n_qubits - 1):
            for i in range(self.dim):
                bits = format(i, f'0{self.n_qubits}b')
                if bits[q] == '1' and bits[q+1] == '1':
                    state[i] *= -1

        return state

# Test implementation
print("Testing State Generator QGAN:")
gen = StateGeneratorQGAN(n_qubits=3, n_layers=3)

# Test GHZ state
ghz = gen.create_ghz_target()
print(f"\nGHZ target (non-zero amplitudes):")
for i, amp in enumerate(ghz):
    if abs(amp) > 1e-10:
        print(f"  |{i:03b}⟩: {amp:.4f}")

fidelity_ghz = gen.compute_fidelity(ghz)
print(f"Initial GHZ fidelity: {fidelity_ghz:.4f}")

# Test W state
w = gen.create_w_target()
print(f"\nW target (non-zero amplitudes):")
for i, amp in enumerate(w):
    if abs(amp) > 1e-10:
        print(f"  |{i:03b}⟩: {amp:.4f}")

fidelity_w = gen.compute_fidelity(w)
print(f"Initial W fidelity: {fidelity_w:.4f}")
